 1	import { Button, Flex, FlexItem, Popover, Text } from '@patternfly/react-core';
 2	import { TimesIcon } from '@patternfly/react-icons';
 3	import React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	
 6	export interface ChipsPopoverProps {
 7	  chipsPopoverMessage?: string;
 8	  setChipsPopoverMessage: (v?: string) => void;
 9	}
10	
11	export const ChipsPopover: React.FC<ChipsPopoverProps> = ({ chipsPopoverMessage, setChipsPopoverMessage }) => {
12	  const { t } = useTranslation('plugin__netobserv-plugin');
13	
14	  if (!chipsPopoverMessage) {
15	    return <></>;
16	  }
17	
18	  return (
19	    <Popover
20	      id="chips-popover"
21	      isVisible={chipsPopoverMessage !== undefined}
22	      hideOnOutsideClick={false}
23	      showClose={false}
24	      position="bottom"
25	      headerContent={
26	        <Flex direction={{ default: 'row' }}>
27	          <FlexItem flex={{ default: 'flex_1' }}>{t('Some filters have been automatically disabled')}</FlexItem>
28	          <FlexItem>
29	            <Button
30	              icon={<TimesIcon />}
31	              variant="plain"
32	              className="chips-popover-close-button"
33	              onClick={() => setChipsPopoverMessage(undefined)}
34	            />
35	          </FlexItem>
36	        </Flex>
37	      }
38	      bodyContent={<Text component="p"> {chipsPopoverMessage}</Text>}
39	      triggerRef={() => document.getElementsByClassName('custom-chip-group disabled-group')?.[0] as HTMLElement}
40	    />
41	  );
42	};
43	
44	export default ChipsPopover;

